const fs = require('fs');

function parseNucleiFile(path) {
  try {
    const content = fs.readFileSync(path, 'utf8');
    return content.trim().split('\n')
      .filter(l => l.trim())
      .map(l => JSON.parse(l));
  } catch (e) {
    return [];
  }
}

function countSeverities(findings) {
  const counts = { critical: 0, high: 0, medium: 0, low: 0, info: 0 };
  for (const f of findings) {
    const sev = (f.info && f.info.severity ? f.info.severity : 'info').toLowerCase();
    if (counts[sev] !== undefined) counts[sev]++;
  }
  return counts;
}

const targets = [
  { name: 'DVWA',      file: '/reports/raw/nuclei_dvwa.json' },
  { name: 'JuiceShop', file: '/reports/raw/nuclei_juiceshop.json' },
  { name: 'WebGoat',   file: '/reports/raw/nuclei_webgoat.json' },
];

const results = targets.map(t => {
  const findings = parseNucleiFile(t.file);
  const counts = countSeverities(findings);
  const score = counts.critical * 10 + counts.high * 7 + counts.medium * 4 + counts.low * 1;
  return { target: t.name, counts, score, total: findings.length };
});

return results.map(r => ({ json: r }));

const items = $input.all();
const date = new Date().toISOString().split('T')[0];

const riskEmoji = (score) => {
  if (score >= 20) return '🔴';
  if (score >= 10) return '🟠';
  if (score >= 1)  return '🟡';
  return '🟢';
};

const fields = items.map(item => {
  const { target, counts, score } = item.json;
  return {
    name: `${riskEmoji(score)} ${target}  (score: ${score})`,
    value: `C:${counts.critical}  H:${counts.high}  M:${counts.medium}  L:${counts.low}  I:${counts.info}  |  total findings: ${item.json.total}`,
    inline: false
  };
});

const totalScore = items.reduce((sum, i) => sum + i.json.score, 0);
const color = totalScore >= 20 ? 15158332 : totalScore >= 10 ? 15105570 : totalScore >= 1 ? 16312092 : 5763719;

return [{
  json: {
    embeds: [{
      title: `VulnForge Scan Report — ${date}`,
      description: `Combined score across all targets: **${totalScore}**`,
      color,
      fields,
      footer: { text: 'Nuclei · n8n · VulnForge' },
      timestamp: new Date().toISOString()
    }]
  }
}];
